void solveLinearSystem(std::vector<COOElement> const& A, std::vector<double> const& b, std::vector<double> &x, size_t N) {
   std::vector<double> matrix_data(N * N, 0.0);
   std::vector<double> b_copy = b;

   for (const auto& element : A) {
      matrix_data[element.row * N + element.column] = element.value;
   }

   x.assign(N, 0.0);

   for (size_t i = 0; i < N; ++i) {
      double maxEl = std::abs(matrix_data[i * N + i]);
      size_t maxRow = i;
      for (size_t k = i + 1; k < N; ++k) {
         double val = matrix_data[k * N + i];
         if (std::abs(val) > maxEl) {
            maxEl = std::abs(val);
            maxRow = k;
         }
      }

      for (size_t k = 0; k < N; ++k) {
         std::swap(matrix_data[maxRow * N + k], matrix_data[i * N + k]);
      }
      std::swap(b_copy[maxRow], b_copy[i]);

      #pragma omp parallel for schedule(static)
      for (size_t k = i + 1; k < N; ++k) {
         double c = -matrix_data[k * N + i] / matrix_data[i * N + i];
         for (size_t j = i; j < N; ++j) {
            if (i == j) {
               matrix_data[k * N + j] = 0.0;
            } else {
               matrix_data[k * N + j] += c * matrix_data[i * N + j];
            }
         }
         b_copy[k] += c * b_copy[i];
      }
   }

   for (int i = N - 1; i >= 0; --i) {
      x[i] = b_copy[i] / matrix_data[i * N + i];
      for (int k = i - 1; k >= 0; --k) {
         b_copy[k] -= matrix_data[k * N + i] * x[i];
      }
   }
}
