int maximumSubarray(std::vector<int> const& x) {
    int n = x.size();
    if (n == 0) {
        return std::numeric_limits<int>::lowest();
    }
    const int numThreads = 8;
    int chunkSize = (n + numThreads - 1) / numThreads;
    int localMax[8];
    for (int i = 0; i < 8; i++) {
        localMax[i] = std::numeric_limits<int>::lowest();
    }

    #pragma omp parallel for schedule(static)
    for (int thread_id = 0; thread_id < 8; thread_id++) {
        int start_i = thread_id * chunkSize;
        int end_i = std::min(start_i + chunkSize, n);
        for (int i = start_i; i < end_i; i++) {
            int currSum = 0;
            for (int j = i; j < n; j++) {
                currSum += x[j];
                if (currSum > localMax[thread_id]) {
                    localMax[thread_id] = currSum;
                }
            }
        }
    }

    int globalMax = std::numeric_limits<int>::lowest();
    for (int i = 0; i < 8; i++) {
        if (localMax[i] > globalMax) {
            globalMax = localMax[i];
        }
    }
    return globalMax;
}
