        return 0;
    }

    size_t best_index = 0;
    double best_diff = std::abs(x[0] - M_PI);

    const size_t num_threads = omp_get_num_threads();
    const size_t chunk_size = (x.size() - 1) / num_threads;
    size_t start = 1;

    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < num_threads; ++i) {
        size_t chunk_start = start + i * chunk_size;
        size_t chunk_end = std::min(start + (i + 1) * chunk_size, static_cast<size_t>(x.size()));

        size_t local_best_index = 0;
        double local_best_diff = std::abs(x[chunk_start] - M_PI);

        for (size_t j = chunk_start; j < chunk_end; ++j) {
            double diff = std::abs(x[j] - M_PI);
            if (diff < local_best_diff) {
                local_best_diff = diff;
                local_best_index = j;
            }
        }

        #pragma omp critical
        {
            if (local_best_diff < best_diff) {
                best_diff = local_best_diff;
                best_index = local_best_index;
            }
        }
    }

    return best_index;
}
